import random
import math
import itertools
from collections import defaultdict

def compute_model_placement(gpu_num, models):
    MEM_LIMIT = 80.0

    if not models:
        return {i: [] for i in range(gpu_num)}

    # Precompute model properties
    for model in models:
        model.load = model.req_rate / model.slo

    def kvpr_of_models(model_list):
        if not model_list:
            return 0.0
        total_size = sum(m.model_size for m in model_list)
        if total_size >= MEM_LIMIT - 1e-9:
            return float('inf')
        total_load = sum(m.load for m in model_list)
        return total_load / (MEM_LIMIT - total_size)

    def max_kvpr(placement):
        max_val = 0.0
        for i in range(gpu_num):
            kvpr = kvpr_of_models(placement[i])
            if kvpr > max_val:
                max_val = kvpr
        return max_val

    # Generate initial placement using multiple heuristics
    best_placement = None
    best_score = float('inf')

    for attempt in range(15):
        placement = {i: [] for i in range(gpu_num)}
        used_mem = [0.0] * gpu_num

        if attempt == 0:
            # Strategy 1: Sort by load density (load/size)
            sorted_models = sorted(models, key=lambda m: m.load/m.model_size if m.model_size > 0 else float('inf'), reverse=True)
            for model in sorted_models:
                best_gpu = -1
                best_increase = float('inf')
                for gpu in range(gpu_num):
                    if used_mem[gpu] + model.model_size <= MEM_LIMIT:
                        # Estimate KVPR increase
                        new_load = sum(m.load for m in placement[gpu]) + model.load
                        new_size = used_mem[gpu] + model.model_size
                        remaining = MEM_LIMIT - new_size
                        if remaining > 1e-9:
                            new_kvpr = new_load / remaining
                            increase = new_kvpr - kvpr_of_models(placement[gpu])
                            if increase < best_increase:
                                best_increase = increase
                                best_gpu = gpu
                if best_gpu != -1:
                    placement[best_gpu].append(model)
                    used_mem[best_gpu] += model.model_size
                else:
                    gpu = min(range(gpu_num), key=lambda i: used_mem[i])
                    placement[gpu].append(model)
                    used_mem[gpu] += model.model_size

        elif attempt == 1:
            # Strategy 2: Sort by size descending
            sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)
            for model in sorted_models:
                candidates = [(i, MEM_LIMIT - used_mem[i]) for i in range(gpu_num)]
                candidates.sort(key=lambda x: x[1], reverse=True)
                placed = False
                for gpu, free in candidates:
                    if free >= model.model_size:
                        placement[gpu].append(model)
                        used_mem[gpu] += model.model_size
                        placed = True
                        break
                if not placed:
                    gpu = min(range(gpu_num), key=lambda i: used_mem[i])
                    placement[gpu].append(model)
                    used_mem[gpu] += model.model_size

        elif attempt == 2:
            # Strategy 3: Sort by load descending
            sorted_models = sorted(models, key=lambda m: m.load, reverse=True)
            for model in sorted_models:
                best_gpu = -1
                min_kvpr = float('inf')
                for gpu in range(gpu_num):
                    if used_mem[gpu] + model.model_size <= MEM_LIMIT:
                        temp_kvpr = kvpr_of_models(placement[gpu] + [model])
                        if temp_kvpr < min_kvpr:
                            min_kvpr = temp_kvpr
                            best_gpu = gpu
                if best_gpu != -1:
                    placement[best_gpu].append(model)
                    used_mem[best_gpu] += model.model_size
                else:
                    gpu = min(range(gpu_num), key=lambda i: used_mem[i])
                    placement[gpu].append(model)
                    used_mem[gpu] += model.model_size

        else:
            # Random strategy with capacity constraint
            random.shuffle(models)
            for model in models:
                candidates = list(range(gpu_num))
                random.shuffle(candidates)
                placed = False
                for gpu in candidates:
                    if used_mem[gpu] + model.model_size <= MEM_LIMIT:
                        placement[gpu].append(model)
                        used_mem[gpu] += model.model_size
                        placed = True
                        break
                if not placed:
                    gpu = min(range(gpu_num), key=lambda i: used_mem[i])
                    placement[gpu].append(model)
                    used_mem[gpu] += model.model_size

        # Simulated annealing for improvement
        current_placement = {i: list(placement[i]) for i in range(gpu_num)}
        current_mem = used_mem[:]
        current_score = max_kvpr(current_placement)

        temperature = 5.0
        min_temp = 0.01
        cooling_rate = 0.95

        while temperature > min_temp:
            for _ in range(50):
                # Try a random move
                src_gpu = random.randrange(gpu_num)
                if not current_placement[src_gpu]:
                    continue

                model = random.choice(current_placement[src_gpu])
                dst_gpu = random.randrange(gpu_num)
                while dst_gpu == src_gpu:
                    dst_gpu = random.randrange(gpu_num)

                if current_mem[dst_gpu] + model.model_size <= MEM_LIMIT:
                    # Create new placement
                    new_placement = {i: list(current_placement[i]) for i in range(gpu_num)}
                    new_placement[src_gpu].remove(model)
                    new_placement[dst_gpu].append(model)

                    new_score = max_kvpr(new_placement)
                    delta = new_score - current_score

                    if delta < 0 or random.random() < math.exp(-delta/temperature):
                        current_placement = new_placement
                        current_score = new_score
                        current_mem[src_gpu] -= model.model_size
                        current_mem[dst_gpu] += model.model_size

            temperature *= cooling_rate

        # Greedy refinement focusing on the most loaded GPU
        for _ in range(100):
            pressures = [kvpr_of_models(current_placement[i]) for i in range(gpu_num)]
            max_gpu = max(range(gpu_num), key=lambda i: pressures[i])

            improved = False
            # Try moving models from max_gpu
            for model in list(current_placement[max_gpu]):
                for dst in range(gpu_num):
                    if dst == max_gpu:
                        continue
                    if current_mem[dst] + model.model_size > MEM_LIMIT:
                        continue

                    # Calculate new pressures
                    new_max_list = [m for m in current_placement[max_gpu] if m != model]
                    new_dst_list = current_placement[dst] + [model]

                    new_max_pressure = kvpr_of_models(new_max_list)
                    new_dst_pressure = kvpr_of_models(new_dst_list)

                    old_max = pressures[max_gpu]
                    new_max = max(new_max_pressure, new_dst_pressure)
                    for gpu in range(gpu_num):
                        if gpu not in (max_gpu, dst):
                            new_max = max(new_max, pressures[gpu])

                    if new_max < old_max - 1e-12:
                        current_placement[max_gpu].remove(model)
                        current_placement[dst].append(model)
                        current_mem[max_gpu] -= model.model_size
                        current_mem[dst] += model.model_size
                        improved = True
                        break
                if improved:
                    break

            if not improved:
                # Try swapping models
                for gpu1 in range(gpu_num):
                    for gpu2 in range(gpu1 + 1, gpu_num):
                        if not current_placement[gpu1] or not current_placement[gpu2]:
                            continue
                        for model1 in list(current_placement[gpu1]):
                            for model2 in list(current_placement[gpu2]):
                                new_mem1 = current_mem[gpu1] - model1.model_size + model2.model_size
                                new_mem2 = current_mem[gpu2] - model2.model_size + model1.model_size

                                if new_mem1 <= MEM_LIMIT and new_mem2 <= MEM_LIMIT:
                                    new_list1 = [m for m in current_placement[gpu1] if m != model1] + [model2]
                                    new_list2 = [m for m in current_placement[gpu2] if m != model2] + [model1]

                                    new_p1 = kvpr_of_models(new_list1)
                                    new_p2 = kvpr_of_models(new_list2)

                                    old_max = max(pressures[gpu1], pressures[gpu2])
                                    new_max = max(new_p1, new_p2)
                                    for gpu in range(gpu_num):
                                        if gpu not in (gpu1, gpu2):
                                            new_max = max(new_max, pressures[gpu])

                                    if new_max < old_max - 1e-12:
                                        current_placement[gpu1].remove(model1)
                                        current_placement[gpu2].remove(model2)
                                        current_placement[gpu1].append(model2)
                                        current_placement[gpu2].append(model1)
                                        current_mem[gpu1] = new_mem1
                                        current_mem[gpu2] = new_mem2
                                        improved = True
                                        break
                            if improved:
                                break
                        if improved:
                            break
                if not improved:
                    break

        final_score = max_kvpr(current_placement)
        if final_score < best_score:
            best_score = final_score
            best_placement = {i: list(current_placement[i]) for i in range(gpu_num)}

    # Ensure all models are placed
    placed_models = sum(len(best_placement[i]) for i in range(gpu_num))
    if placed_models != len(models):
        # Fallback: put all models on first GPU
        best_placement = {i: [] for i in range(gpu_num)}
        best_placement[0] = list(models)

    return best_placement

