from collections import defaultdict

def compute_model_placement(gpu_num, models):
    def kvpr(model_list):
        if not model_list:
            return 0.0
        total_size = sum(m.model_size for m in model_list)
        if total_size >= 80:
            return float('inf')
        total_load = sum(m.req_rate / m.slo for m in model_list)
        return total_load / (80 - total_size)

    def max_kvpr(placement):
        return max(kvpr(placement[g]) for g in range(gpu_num))

    best_placement = None
    best_score = float('inf')

    for init_try in range(20):
        placement = {g: [] for g in range(gpu_num)}
        used_mem = [0] * gpu_num

        if init_try < 8:
            sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo) / m.model_size, reverse=True)
        elif init_try < 16:
            sorted_models = sorted(models, key=lambda m: m.req_rate / m.slo, reverse=True)
        else:
            sorted_models = models[:]
            random.shuffle(sorted_models)

        for model in sorted_models:
            candidates = []
            for g in range(gpu_num):
                if used_mem[g] + model.model_size <= 80:
                    current_kvpr = kvpr(placement[g])
                    new_kvpr = kvpr(placement[g] + [model])
                    candidates.append((g, new_kvpr - current_kvpr))

            if candidates:
                best_gpu = min(candidates, key=lambda x: x[1])[0]
                placement[best_gpu].append(model)
                used_mem[best_gpu] += model.model_size
            else:
                best_gpu = min(range(gpu_num), key=lambda g: used_mem[g])
                if used_mem[best_gpu] + model.model_size <= 80:
                    placement[best_gpu].append(model)
                    used_mem[best_gpu] += model.model_size

        current_placement = {g: placement[g][:] for g in range(gpu_num)}
        current_mem = used_mem[:]
        current_score = max_kvpr(current_placement)

        temperature = 5.0
        cooling_rate = 0.97
        iterations = 3000

        for it in range(iterations):
            if it % 100 == 0:
                kvprs = [kvpr(current_placement[g]) for g in range(gpu_num)]
                max_gpu = max(range(gpu_num), key=lambda g: kvprs[g])
                min_gpu = min(range(gpu_num), key=lambda g: kvprs[g])

                if max_gpu != min_gpu and current_placement[max_gpu]:
                    improved = False
                    for model in current_placement[max_gpu][:]:
                        if current_mem[min_gpu] + model.model_size <= 80:
                            new_max_kvpr = kvpr([m for m in current_placement[max_gpu] if m != model])
                            new_min_kvpr = kvpr(current_placement[min_gpu] + [model])
                            new_max = max(new_max_kvpr, new_min_kvpr,
                                         max(kvprs[g] for g in range(gpu_num) if g not in (max_gpu, min_gpu)))

                            if new_max < current_score:
                                current_placement[max_gpu].remove(model)
                                current_placement[min_gpu].append(model)
                                current_mem[max_gpu] -= model.model_size
                                current_mem[min_gpu] += model.model_size
                                current_score = new_max
                                improved = True
                                break

                    if improved:
                        temperature *= cooling_rate
                        continue

            move_type = random.random()

            if move_type < 0.8:
                src = random.choice([g for g in range(gpu_num) if current_placement[g]])
                if not current_placement[src]:
                    temperature *= cooling_rate
                    continue

                model_idx = random.randrange(len(current_placement[src]))
                model = current_placement[src][model_idx]

                candidates = []
                for dst in range(gpu_num):
                    if dst != src and current_mem[dst] + model.model_size <= 80:
                        candidates.append(dst)

                if candidates:
                    dst = random.choice(candidates)

                    new_src_list = current_placement[src][:]
                    new_src_list.pop(model_idx)
                    new_dst_list = current_placement[dst] + [model]

                    new_src_kvpr = kvpr(new_src_list)
                    new_dst_kvpr = kvpr(new_dst_list)
                    new_max = max(new_src_kvpr, new_dst_kvpr,
                                 max(kvpr(current_placement[g]) for g in range(gpu_num) if g not in (src, dst)))

                    delta = new_max - current_score

                    if delta < 0 or random.random() < math.exp(-delta / temperature):
                        current_placement[src] = new_src_list
                        current_placement[dst] = new_dst_list
                        current_mem[src] -= model.model_size
                        current_mem[dst] += model.model_size
                        current_score = new_max

            elif move_type < 0.95:
                g1, g2 = random.sample(range(gpu_num), 2)
                if not current_placement[g1] or not current_placement[g2]:
                    temperature *= cooling_rate
                    continue

                i = random.randrange(len(current_placement[g1]))
                j = random.randrange(len(current_placement[g2]))
                m1, m2 = current_placement[g1][i], current_placement[g2][j]

                if (current_mem[g1] - m1.model_size + m2.model_size <= 80 and
                    current_mem[g2] - m2.model_size + m1.model_size <= 80):

                    new_g1_list = current_placement[g1][:]
                    new_g2_list = current_placement[g2][:]
                    new_g1_list[i] = m2
                    new_g2_list[j] = m1

                    new_g1_kvpr = kvpr(new_g1_list)
                    new_g2_kvpr = kvpr(new_g2_list)
                    new_max = max(new_g1_kvpr, new_g2_kvpr,
