                        current_placement[g1] = new_g1_list
                        current_placement[g2] = new_g2_list
                        current_mem[g1] = current_mem[g1] - m1.model_size + m2.model_size
                        current_mem[g2] = current_mem[g2] - m2.model_size + m1.model_size
                        current_score = new_max

            temperature *= cooling_rate

        for refine_iter in range(50):
            kvprs = [kvpr(current_placement[g]) for g in range(gpu_num)]
            max_gpu = max(range(gpu_num), key=lambda g: kvprs[g])

            if not current_placement[max_gpu]:
                break

            best_move = None
            best_new_max = current_score

            for model_idx, model in enumerate(current_placement[max_gpu]):
                for dst in range(gpu_num):
                    if dst == max_gpu:
                        continue
                    if current_mem[dst] + model.model_size > 80:
                        continue

                    new_max_kvpr = kvpr([m for m in current_placement[max_gpu] if m != model])
                    new_dst_kvpr = kvpr(current_placement[dst] + [model])
                    new_max = max(new_max_kvpr, new_dst_kvpr,
                                 max(kvprs[g] for g in range(gpu_num) if g not in (max_gpu, dst)))

                    if new_max < best_new_max:
                        best_new_max = new_max
                        best_move = (model_idx, model, dst)

            if best_move:
                model_idx, model, dst = best_move
                current_placement[max_gpu].pop(model_idx)
                current_placement[dst].append(model)
                current_mem[max_gpu] -= model.model_size
                current_mem[dst] += model.model_size
                current_score = best_new_max
            else:
                break

        final_score = current_score
        if final_score < best_score:
            best_score = final_score
            best_placement = {g: current_placement[g][:] for g in range(gpu_num)}

