def compute_model_placement(gpu_num, models):
    MEM_LIMIT = 80

    def kvpr(model_list):
        if not model_list:
            return 0.0
        total_size = sum(m.model_size for m in model_list)
        if total_size >= MEM_LIMIT:
            return float('inf')
        total_load = sum(m.req_rate / m.slo for m in model_list)
        denominator = MEM_LIMIT - total_size
        if denominator <= 1e-12:
            return float('inf')
        return total_load / denominator

    def max_kvpr(placement):
        return max(kvpr(placement[g]) for g in range(gpu_num))

    best_placement = None
    best_score = float('inf')

    for seed in range(10):
        random.seed(seed)
        placement = {g: [] for g in range(gpu_num)}
        used_mem = [0] * gpu_num

        sorted_models = sorted(
            models,
            key=lambda m: (m.req_rate / m.slo) / m.model_size if m.model_size > 0 else 0,
            reverse=True
        )

        for model in sorted_models:
            candidates = []
            for g in range(gpu_num):
                if used_mem[g] + model.model_size <= MEM_LIMIT:
                    old_kvpr_val = kvpr(placement[g])
                    new_kvpr_val = kvpr(placement[g] + [model])
                    candidates.append((new_kvpr_val - old_kvpr_val, g))

            if candidates:
                candidates.sort()
                best_gpu = candidates[0][1]
            else:
                best_gpu = max(range(gpu_num), key=lambda g: MEM_LIMIT - used_mem[g])

            placement[best_gpu].append(model)
            used_mem[best_gpu] += model.model_size

        current_placement = {g: placement[g][:] for g in range(gpu_num)}
        current_mem = used_mem[:]
        current_score = max_kvpr(current_placement)

        temp = 1.0
        cooling = 0.995
        for _ in range(3000):
            if random.random() < 0.7:
                src = random.randrange(gpu_num)
                if not current_placement[src]:
                    temp *= cooling
                    continue
                midx = random.randrange(len(current_placement[src]))
                model = current_placement[src][midx]
                dst = random.randrange(gpu_num)
                if dst == src:
                    temp *= cooling
                    continue
                if current_mem[dst] + model.model_size <= MEM_LIMIT:
                    new_placement = {g: current_placement[g][:] for g in range(gpu_num)}
                    new_mem = current_mem[:]
                    new_placement[src].pop(midx)
                    new_placement[dst].append(model)
                    new_mem[src] -= model.model_size
                    new_mem[dst] += model.model_size
                    new_score = max_kvpr(new_placement)
                    delta = new_score - current_score
                    if delta < 0 or (temp > 1e-12 and random.random() < math.exp(-delta / temp)):
                        current_placement = new_placement
                        current_mem = new_mem
                        current_score = new_score
                        if new_score < best_score:
                            best_score = new_score
                            best_placement = {g: new_placement[g][:] for g in range(gpu_num)}
            else:
                g1, g2 = random.sample(range(gpu_num), 2)
                if not current_placement[g1] or not current_placement[g2]:
                    temp *= cooling
                    continue
                i1 = random.randrange(len(current_placement[g1]))
                i2 = random.randrange(len(current_placement[g2]))
                m1, m2 = current_placement[g1][i1], current_placement[g2][i2]
                if (current_mem[g1] - m1.model_size + m2.model_size <= MEM_LIMIT and
                    current_mem[g2] - m2.model_size + m1.model_size <= MEM_LIMIT):
                    new_placement = {g: current_placement[g][:] for g in range(gpu_num)}
                    new_mem = current_mem[:]
                    new_placement[g1][i1] = m2
                    new_placement[g2][i2] = m1
                    new_mem[g1] = new_mem[g1] - m1.model_size + m2.model_size
                    new_mem[g2] = new_mem[g2] - m2.model_size + m1.model_size
                    new_score = max_kvpr(new_placement)
                    delta = new_score - current_score
                    if delta < 0 or (temp > 1e-12 and random.random() < math.exp(-delta / temp)):
                        current_placement = new_placement
                        current_mem = new_mem
                        current_score = new_score
                        if new_score < best_score:
                            best_score = new_score
                            best_placement = {g: new_placement[g][:] for g in range(gpu_num)}
            temp *= cooling

    if best_placement is None:
        best_placement = {g: [] for g in range(gpu_num)}

    used_mem = [sum(m.model_size for m in best_placement[g]) for g in range(gpu_num)]

    for _ in range(100):
        pressures = [kvpr(best_placement[g]) for g in range(gpu_num)]
        max_gpu = max(range(gpu_num), key=lambda g: pressures[g])
        improved = False
        for model in list(best_placement[max_gpu]):
            for dst in range(gpu_num):
                if dst == max_gpu:
                    continue
                if used_mem[dst] + model.model_size > MEM_LIMIT:
                    continue
                old_src_kvpr = kvpr(best_placement[max_gpu])
                old_dst_kvpr = kvpr(best_placement[dst])
                new_src_list = [m for m in best_placement[max_gpu] if m is not model]
                new_dst_list = best_placement[dst] + [model]
                new_src_kvpr = kvpr(new_src_list)
                new_dst_kvpr = kvpr(new_dst_list)
                old_max = max(pressures[max_gpu], pressures[dst])
                new_max = max(new_src_kvpr, new_dst_kvpr)
                for g in range(gpu_num):
                    if g not in (max_gpu, dst):
                        old_max = max(old_max, pressures[g])
                        new_max = max(new_max, pressures[g])
                if new_max < old_max:
                    best_placement[max_gpu].remove(model)
                    best_placement[dst].append(model)
                    used_mem[max_gpu] -= model.model_size
                    used_mem[dst] += model.model_size
                    improved = True
                    break
            if improved:
                break
        if not improved:
            break

    return best_placement

def compute_model_placement(gpu_num, models):
    import random
    import math
    import numpy as np
    from collections import defaultdict
    import heapq

    def calculate_kvpr(gpu_models, gpu_memory_limit=80):
        if not gpu_models:
            return 0.0
        total_size = sum(m.model_size for m in gpu_models)
        total_load = sum(m.req_rate / m.slo for m in gpu_models)
        remaining_mem = gpu_memory_limit - total_size
        if remaining_mem <= 0:
            return float('inf')
        return total_load / remaining_mem if remaining_mem > 0 else float('inf')

    def get_max_kvpr(placement):
        max_k = 0.0
        for gpu_id in placement:
            max_k = max(max_k, calculate_kvpr(placement[gpu_id]))
        return max_k

    # Initial placement using greedy bin packing
    models_sorted = sorted(
        models,
        key=lambda m: (m.req_rate / m.slo) / max(m.model_size, 1),
        reverse=True
    )

    placement = {i: [] for i in range(gpu_num)}
    gpu_current_sizes = [0] * gpu_num

    for model in models_sorted:
        best_gpu_id = -1
        min_potential_max_kvpr = float('inf')
        best_gpu_load_for_balancing = float('inf')

        for gpu_id in range(gpu_num):
            if gpu_current_sizes[gpu_id] + model.model_size <= 80:
                temp_placement = placement[gpu_id] + [model]
                current_gpu_kvpr = calculate_kvpr(temp_placement)

                # Calculate potential max KVPR with this model added
                temp_placement_dict = {g: (placement[g] + [model] if g == gpu_id else placement[g]) for g in range(gpu_num)}
                potential_max_kvpr = get_max_kvpr(temp_placement_dict)

                if potential_max_kvpr < min_potential_max_kvpr:
                    min_potential_max_kvpr = potential_max_kvpr
                    best_gpu_id = gpu_id
                    best_gpu_load_for_balancing = current_gpu_kvpr
                elif potential_max_kvpr == min_potential_max_kvpr:
                    if current_gpu_kvpr < best_gpu_load_for_balancing:
                        best_gpu_id = gpu_id
                        best_gpu_load_for_balancing = current_gpu_kvpr

        if best_gpu_id != -1:
            placement[best_gpu_id].append(model)
            gpu_current_sizes[best_gpu_id] += model.model_size
        else:
            # Fallback
            most_free_gpu_id = min(range(gpu_num), key=lambda g: 80 - gpu_current_sizes[g])
            placement[most_free_gpu_id].append(model)
            gpu_current_sizes[most_free_gpu_id] += model.model_size

    # Local search with simulated annealing
    current_placement = {g: list(placement[g]) for g in range(gpu_num)}
    current_max_kvpr = get_max_kvpr(current_placement)
    current_gpu_sizes = gpu_current_sizes[:]

    best_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
    best_max_kvpr = current_max_kvpr

    temperature = 1000.0
    cooling_rate = 0.995
    min_temperature = 1e-8
    max_iterations = 5000

    for iteration in range(max_iterations):
        if temperature < min_temperature:
            break

        move_type_prob = random.random()
        prev_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
        prev_gpu_sizes = current_gpu_sizes[:]
        prev_max_kvpr = current_max_kvpr

        if move_type_prob < 0.6:  # Move single model
            source_gpus = [g for g in range(gpu_num) if current_placement[g]]
            if not source_gpus:
                continue
            src_gpu_id = random.choice(source_gpus)

            if not current_placement[src_gpu_id]:
                continue

            model_to_move_idx = random.randrange(len(current_placement[src_gpu_id]))
            model_to_move = current_placement[src_gpu_id][model_to_move_idx]

            candidate_dests = []
            for dest_gpu_id in range(gpu_num):
                if src_gpu_id == dest_gpu_id:
                    continue
                if current_gpu_sizes[dest_gpu_id] + model_to_move.model_size <= 80:
                    candidate_dests.append(dest_gpu_id)

            if candidate_dests:
                best_dest_gpu_id = -1
                min_new_max_kvpr = float('inf')

                for dest_gpu_id in candidate_dests:
                    temp_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
                    temp_gpu_sizes = current_gpu_sizes[:]

                    temp_placement[src_gpu_id].pop(model_to_move_idx)
                    temp_placement[dest_gpu_id].append(model_to_move)
                    temp_gpu_sizes[src_gpu_id] -= model_to_move.model_size
                    temp_gpu_sizes[dest_gpu_id] += model_to_move.model_size

                    new_max_kvpr = get_max_kvpr(temp_placement)

                    if new_max_kvpr < min_new_max_kvpr:
                        min_new_max_kvpr = new_max_kvpr
                        best_dest_gpu_id = dest_gpu_id

                if best_dest_gpu_id != -1:
                    current_placement[src_gpu_id].pop(model_to_move_idx)
                    current_placement[best_dest_gpu_id].append(model_to_move)
                    current_gpu_sizes[src_gpu_id] -= model_to_move.model_size
                    current_gpu_sizes[best_dest_gpu_id] += model_to_move.model_size
                    current_max_kvpr = min_new_max_kvpr

        elif move_type_prob < 0.9:  # Swap two models
            gpu_pairs = [(i, j) for i in range(gpu_num) for j in range(i + 1, gpu_num)
                         if current_placement[i] and current_placement[j]]
            if not gpu_pairs:
                continue
            src_gpu_id, dest_gpu_id = random.choice(gpu_pairs)

            if not current_placement[src_gpu_id] or not current_placement[dest_gpu_id]:
                continue

            model1_idx = random.randrange(len(current_placement[src_gpu_id]))
            model2_idx = random.randrange(len(current_placement[dest_gpu_id]))
            model1 = current_placement[src_gpu_id][model1_idx]
            model2 = current_placement[dest_gpu_id][model2_idx]

            new_src_size = current_gpu_sizes[src_gpu_id] - model1.model_size + model2.model_size
            new_dest_size = current_gpu_sizes[dest_gpu_id] - model2.model_size + model1.model_size

            if new_src_size <= 80 and new_dest_size <= 80:
                current_placement[src_gpu_id][model1_idx] = model2
                current_placement[dest_gpu_id][model2_idx] = model1
                current_gpu_sizes[src_gpu_id] = new_src_size
                current_gpu_sizes[dest_gpu_id] = new_dest_size
                current_max_kvpr = get_max_kvpr(current_placement)

        else:  # Move from high KVPR to low KVPR
            kvpr_values = [calculate_kvpr(current_placement[g]) for g in range(gpu_num)]
            if not any(kvpr_values):
                continue

            high_kvpr_gpu_id = max(range(gpu_num), key=lambda g: kvpr_values[g])

            low_kvpr_options = sorted(
                [(kvpr_values[g], g) for g in range(gpu_num) if g != high_kvpr_gpu_id and current_gpu_sizes[g] < 80],
                key=lambda x: x[0]
            )

            if current_placement[high_kvpr_gpu_id] and low_kvpr_options:
                best_low_gpu_id = low_kvpr_options[0][1]

                for model_idx, model_to_move in enumerate(current_placement[high_kvpr_gpu_id]):
                    if current_gpu_sizes[best_low_gpu_id] + model_to_move.model_size <= 80:
                        temp_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
                        temp_gpu_sizes = current_gpu_sizes[:]

                        temp_placement[high_kvpr_gpu_id].pop(model_idx)
                        temp_placement[best_low_gpu_id].append(model_to_move)
                        temp_gpu_sizes[high_kvpr_gpu_id] -= model_to_move.model_size
                        temp_gpu_sizes[best_low_gpu_id] += model_to_move.model_size

                        new_max_kvpr = get_max_kvpr(temp_placement)

                        if new_max_kvpr < current_max_kvpr:
                            current_placement = temp_placement
                            current_gpu_sizes = temp_gpu_sizes
                            current_max_kvpr = new_max_kvpr
                            break

        # Accept or reject
        delta = current_max_kvpr - prev_max_kvpr
        if delta < 0 or random.random() < math.exp(-delta / temperature):
            if current_max_kvpr < best_max_kvpr:
                best_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
                best_max_kvpr = current_max_kvpr
        else:
            current_placement = prev_placement
            current_gpu_sizes = prev_gpu_sizes
            current_max_kvpr = prev_max_kvpr

        temperature *= cooling_rate

        if best_max_kvpr == 0:
            break

    # Final refinement
    for _ in range(50):
        kvpr_values = [calculate_kvpr(best_placement[g]) for g in range(gpu_num)]
        if not any(kvpr_values):
            break

        high_kvpr_gpu_id = max(range(gpu_num), key=lambda g: kvpr_values[g])
        low_kvpr_gpu_id = min(range(gpu_num), key=lambda g: kvpr_values[g])

        if high_kvpr_gpu_id == low_kvpr_gpu_id or not best_placement[high_kvpr_gpu_id]:
            break

        moved_model = False
        current_gpu_sizes = [sum(m.model_size for m in best_placement[g]) for g in range(gpu_num)]

        for model_idx in range(len(best_placement[high_kvpr_gpu_id])):
            model_to_move = best_placement[high_kvpr_gpu_id][model_idx]

            if current_gpu_sizes[low_kvpr_gpu_id] + model_to_move.model_size <= 80:
                temp_placement = {g: list(best_placement[g]) for g in range(gpu_num)}
                temp_gpu_sizes = current_gpu_sizes[:]

                temp_placement[high_kvpr_gpu_id].pop(model_idx)
                temp_placement[low_kvpr_gpu_id].append(model_to_move)
                temp_gpu_sizes[high_kvpr_gpu_id] -= model_to_move.model_size
                temp_gpu_sizes[low_kvpr_gpu_id] += model_to_move.model_size

                new_max_kvpr = get_max_kvpr(temp_placement)

                if new_max_kvpr < best_max_kvpr:
                    best_placement = temp_placement
                    best_max_kvpr = new_max_kvpr
                    moved_model = True
                    break

        if not moved_model:
            break

    # Memory constraint check
    for gpu_id in range(gpu_num):
        gpu_size = sum(m.model_size for m in best_placement[gpu_id])
        if gpu_size > 80:
            # Move models to correct GPU
            models_to_move = sorted(
                best_placement[gpu_id],
                key=lambda m: m.model_size,
                reverse=True
            )
            for model in models_to_move:
                if sum(m.model_size for m in best_placement[gpu_id]) <= 80:
                    break
                for dest_gpu in range(gpu_num):
                    if dest_gpu == gpu_id:
                        continue
                    dest_size = sum(m.model_size for m in best_placement[dest_gpu])
                    if dest_size + model.model_size <= 80:
                        best_placement[gpu_id].remove(model)
                        best_placement[dest_gpu].append(model)
                        break

    return best_placement

