def compute_model_placement(gpu_num, models):
    GPU_MEM = 80

    for m in models:
        m.load = m.req_rate / m.slo

    def gpu_kvpr(gpu_models):
        if not gpu_models:
            return 0.0
        total_size = sum(m.model_size for m in gpu_models)
        total_load = sum(m.load for m in gpu_models)
        remaining = GPU_MEM - total_size
        if remaining <= 0:
            return float('inf')
        return total_load / remaining

    def max_kvpr(placement):
        max_val = 0.0
        for i in range(gpu_num):
            kvpr = gpu_kvpr(placement[i])
            if kvpr > max_val:
                max_val = kvpr
        return max_val

    def gpu_stats(placement):
        stats = []
        for i in range(gpu_num):
            models_on = placement[i]
            size = sum(m.model_size for m in models_on)
            load = sum(m.load for m in models_on)
            remain = GPU_MEM - size
            kvpr = load / remain if remain > 0 else float('inf')
            stats.append({
                'size': size,
                'load': load,
                'remain': remain,
                'kvpr': kvpr
            })
        return stats

    sorted_models = sorted(models, key=lambda m: (m.load / m.model_size, m.load), reverse=True)
    placement = {i: [] for i in range(gpu_num)}
    used_mem = [0] * gpu_num
    used_load = [0.0] * gpu_num

    for model in sorted_models:
        best_gpu = -1
        best_kvpr = float('inf')
        for gpu_id in range(gpu_num):
            if used_mem[gpu_id] + model.model_size <= GPU_MEM:
                new_load = used_load[gpu_id] + model.load
                new_mem = used_mem[gpu_id] + model.model_size
                remain = GPU_MEM - new_mem
                if remain > 0:
                    kvpr = new_load / remain
                    if kvpr < best_kvpr:
                        best_kvpr = kvpr
                        best_gpu = gpu_id
        if best_gpu == -1:
            best_gpu = min(range(gpu_num), key=lambda g: used_mem[g])
        placement[best_gpu].append(model)
        used_mem[best_gpu] += model.model_size
        used_load[best_gpu] += model.load

    current = {i: list(placement[i]) for i in range(gpu_num)}
    current_kvpr = max_kvpr(current)
    best = {i: list(current[i]) for i in range(gpu_num)}
    best_kvpr = current_kvpr

    temp = 2.5
    final_temp = 0.005
    cooling = 0.93
    iter_per_temp = 200

    while temp > final_temp:
        for _ in range(iter_per_temp):
            stats = gpu_stats(current)
            worst_gpu = max(range(gpu_num), key=lambda g: stats[g]['kvpr'])

            if not current[worst_gpu]:
                continue

            move_type = random.random()
            new_place = {i: list(current[i]) for i in range(gpu_num)}

            if move_type < 0.7:
                model_to_move = random.choice(current[worst_gpu])
                dest = random.choice([i for i in range(gpu_num) if i != worst_gpu])

                if stats[dest]['size'] + model_to_move.model_size <= GPU_MEM:
                    new_place[worst_gpu].remove(model_to_move)
