                src_new_size = stats[src_gpu]['size'] - model1.model_size + model2.model_size
                dest_new_size = stats[dest_gpu]['size'] - model2.model_size + model1.model_size

                if src_new_size <= GPU_MEM and dest_new_size <= GPU_MEM:
                    new_place[src_gpu].remove(model1)
                    new_place[dest_gpu].remove(model2)
                    new_place[src_gpu].append(model2)
