            new_kvpr = max_kvpr(new_place)
            delta = new_kvpr - current_kvpr

            if delta < 0 or random.random() < math.exp(-delta / temp):
                current = new_place
                current_kvpr = new_kvpr
                if new_kvpr < best_kvpr:
                    best = {i: list(new_place[i]) for i in range(gpu_num)}
                    best_kvpr = new_kvpr

        temp *= cooling

    improved = True
    while improved:
        improved = False
        stats = gpu_stats(best)
        worst_gpu = max(range(gpu_num), key=lambda g: stats[g]['kvpr'])

        for model in list(best[worst_gpu]):
            for dest in range(gpu_num):
                if dest == worst_gpu:
                    continue
                if stats[dest]['size'] + model.model_size <= GPU_MEM:
                    old_kvpr = stats[worst_gpu]['kvpr']
                    new_load_dest = stats[dest]['load'] + model.load
                    new_size_dest = stats[dest]['size'] + model.model_size
                    remain_dest = GPU_MEM - new_size_dest
                    if remain_dest <= 0:
                        continue
                    new_kvpr_dest = new_load_dest / remain_dest

                    new_load_src = stats[worst_gpu]['load'] - model.load
                    new_size_src = stats[worst_gpu]['size'] - model.model_size
                    remain_src = GPU_MEM - new_size_src
                    if remain_src <= 0:
                        new_kvpr_src = 0.0
                    else:
                        new_kvpr_src = new_load_src / remain_src

                    potential_max = max(new_kvpr_dest, new_kvpr_src)
                    if potential_max < best_kvpr:
                        best[worst_gpu].remove(model)
                        best[dest].append(model)
                        best_kvpr = potential_max
                        improved = True
                        break
            if improved:
                break

    return best

