            if current_max_kvpr < best_max_kvpr:
                best_placement = {i: list(current_placement[i]) for i in range(gpu_num)}
                best_max_kvpr = current_max_kvpr

        # Cool down the temperature
        temperature *= cooling_rate
        if temperature < 1e-10:
            temperature = 1e-10

    return best_placement

import random
import math
from collections import defaultdict

def compute_model_placement(gpu_num, models):
    def kvpr(model_list):
        if not model_list:
            return 0.0
        total_size = sum(m.model_size for m in model_list)
        if total_size >= 80:
            return float('inf')
        total_load = sum(m.req_rate / m.slo for m in model_list)
        return total_load / (80 - total_size)

    def max_kvpr(placement):
        return max(kvpr(placement[g]) for g in range(gpu_num))

    # Initialize placement with greedy assignment
    placement = {g: [] for g in range(gpu_num)}
    used_mem = [0] * gpu_num

    # Sort models by (req_rate/slo) / model_size in descending order
    sorted_models = sorted(models, key=lambda m: (m.req_rate/m.slo)/m.model_size, reverse=True)

    for model in sorted_models:
        # Find best GPU based on minimal memory usage
        best_gpu = min(range(gpu_num), key=lambda g: used_mem[g])
        if used_mem[best_gpu] + model.model_size <= 80:
            placement[best_gpu].append(model)
            used_mem[best_gpu] += model.model_size
        else:
            # If no GPU can accommodate, assign to the least loaded one
            best_gpu = min(range(gpu_num), key=lambda g: used_mem[g])
            placement[best_gpu].append(model)
            used_mem[best_gpu] += model.model_size

    # Local search optimization
    improved = True
    while improved:
        improved = False
        pressures = [kvpr(placement[g]) for g in range(gpu_num)]
        max_pressure = max(pressures)

        for gpu_id in range(gpu_num):
            if kvpr(placement[gpu_id]) == max_pressure:
                for model in list(placement[gpu_id]):
                    for target_gpu in range(gpu_num):
                        if target_gpu == gpu_id:
                            continue
                        if used_mem[target_gpu] + model.model_size <= 80:
                            # Calculate pressures after moving
                            old_src_pressure = kvpr([m for m in placement[gpu_id] if m != model])
                            old_dst_pressure = kvpr(placement[target_gpu] + [model])
                            new_max_pressure = max(old_src_pressure, old_dst_pressure)

                            if new_max_pressure < max_pressure:
                                placement[gpu_id].remove(model)
                                placement[target_gpu].append(model)
                                used_mem[gpu_id] -= model.model_size
                                used_mem[target_gpu] += model.model_size
                                improved = True
                                break
                    if improved:
                        break

    # Final simulated annealing refinement
    current_placement = {g: placement[g][:] for g in range(gpu_num)}
    current_score = max_kvpr(current_placement)

    temperature = 1.0
    cooldown_rate = 0.995
    iterations = 5000

    for _ in range(iterations):
        # Pick a random model from a random GPU
        source_gpu = random.randrange(gpu_num)
        if not current_placement[source_gpu]:
            continue

        model_idx = random.randrange(len(current_placement[source_gpu]))
        model = current_placement[source_gpu][model_idx]

        # Try moving to a random GPU
        target_gpu = random.randrange(gpu_num)
        if target_gpu == source_gpu:
            continue

        if used_mem[target_gpu] + model.model_size > 80:
            continue

        # Perform the move
        temp_placement = {g: current_placement[g][:] for g in range(gpu_num)}
        temp_placement[source_gpu].remove(model)
        temp_placement[target_gpu].append(model)

        new_score = max_kvpr(temp_placement)

        # Accept or reject based on temperature
        if new_score < current_score or random.random() < math.exp((current_score - new_score) / temperature):
            current_placement = temp_placement
            current_score = new_score

        temperature *= cooldown_rate

    return current_placement
